const mongoose = require('mongoose');
require('dotenv').config({ path: '.env.local' });
if (!process.env.MONGODB_URI) { console.error('❌ MONGODB_URI missing'); process.exit(1); }

const schema = new mongoose.Schema({
  name: String, brand: { type: String, default: '' },
  category: String, description: String,
  price: Number, mrp: Number,
  stock: { type: Number, default: 100 },
  unit: { type: String, default: 'Piece (nos)' },
  images: { type: Array, default: [] },
  specifications: { type: Array, default: [] },
  variants: { type: Array, default: [] },
  featured: { type: Boolean, default: false },
  trending: { type: Boolean, default: false },
  isActive: { type: Boolean, default: true },
  ratings: { type: Number, default: 0 },
  numReviews: { type: Number, default: 0 },
}, { timestamps: true });

const Product = mongoose.model('Product', schema);
