async function run() {
  console.log('\n🛒 L MART — Seeding 1339 products');
  console.log('==========================================');
  await mongoose.connect(process.env.MONGODB_URI);
  console.log('✅ MongoDB connected\n');
  let added=0, skipped=0, errors=0;
  for(const p of DATA){
    try{
      const exists = await Product.findOne({name:p.name}).lean();
      if(exists){skipped++;continue;}
      await Product.create({
        name:p.name, brand:p.brand||'',
        category:p.category,
        description:p.description||p.name,
        price:Number(p.price),
        mrp:Number(p.mrp)||Number(p.price)*1.1,
        stock:100, unit:p.unit||'Piece (nos)',
        images:[], specifications:[], variants:[],
        featured:false, trending:false, isActive:true,
        ratings:0, numReviews:0,
      });
      added++;
      if(added%100===0) console.log(`  ✅ ${added} added...`);
    }catch(e){errors++;if(errors<=3)console.log(`  ⚠ ${p.name}: ${e.message}`);}
  }
  const total = await Product.countDocuments();
  console.log('\n🎉 Complete!');
  console.log(`  ✅ Added   : ${added}`);
  console.log(`  ⏭  Skipped : ${skipped}`);
  console.log(`  ❌ Errors  : ${errors}`);
  console.log(`  📦 Total   : ${total}\n`);
  await mongoose.disconnect(); process.exit(0);
}
run().catch(e=>{console.error('❌',e.message);process.exit(1);});
